	@Test
	void omniSubjectStarPreservesPredicateFanoutMultiplicity() {
		int centers = 50;
		int[] fanouts = { 1, 3, 1, 2, 1, 4, 1 };
		IRI[] predicates = predicates("urn:omni-accuracy:star:p", fanouts.length);
		StubSketchStatementSource store = new StubSketchStatementSource();
		for (int centerIndex = 0; centerIndex < centers; centerIndex++) {
			Resource center = iri("urn:omni-accuracy:star:center:" + centerIndex);
			for (int predicateIndex = 0; predicateIndex < predicates.length; predicateIndex++) {
				for (int leafIndex = 0; leafIndex < fanouts[predicateIndex]; leafIndex++) {
					store.add(st(center, predicates[predicateIndex],
							iri("urn:omni-accuracy:star:leaf:" + centerIndex + ':' + predicateIndex + ':'
									+ leafIndex)));
				}
			}
		}

		SketchBasedJoinEstimator estimator = track(new SketchBasedJoinEstimator(store, omniConfig()));
		estimator.rebuild();

		List<StatementPattern> starPatterns = new ArrayList<>();
		for (int predicateIndex = 0; predicateIndex < predicates.length; predicateIndex++) {
			starPatterns.add(pattern("center", predicates[predicateIndex], "leaf" + predicateIndex));
		}
		long expected = centers * product(fanouts);

		JoinFrequencyEstimate surface = estimator.estimateSubjectStarJoinSurface(starPatterns, "center");
		assertTrue(surface != null, "Expected direct OMNI subject-star surface estimate");
		assertWithin50Percent("star direct surface", surface.calibratedRows(), expected);
		assertWithin50Percent("star fanout", estimator.cardinality(new ArrayList<>(starPatterns)), expected);
	}

	@Test
	void omniDirectedPathPropagatesObjectWitnessesAcrossHops() {
		int roots = 50;
		int[] fanouts = { 3, 1, 4, 1, 2, 1 };
		IRI[] predicates = predicates("urn:omni-accuracy:path:p", fanouts.length);
		StubSketchStatementSource store = new StubSketchStatementSource();
		List<Resource> subjects = new ArrayList<>(roots);
		for (int rootIndex = 0; rootIndex < roots; rootIndex++) {
			subjects.add(iri("urn:omni-accuracy:path:0:" + rootIndex));
		}
		for (int hop = 0; hop < predicates.length; hop++) {
			List<Resource> nextSubjects = new ArrayList<>(subjects.size() * fanouts[hop]);
			for (int subjectIndex = 0; subjectIndex < subjects.size(); subjectIndex++) {
				Resource subject = subjects.get(subjectIndex);
				for (int edge = 0; edge < fanouts[hop]; edge++) {
					Resource object = iri("urn:omni-accuracy:path:" + (hop + 1) + ':'
							+ (subjectIndex * fanouts[hop] + edge));
					store.add(st(subject, predicates[hop], object));
					nextSubjects.add(object);
				}
			}
			subjects = nextSubjects;
		}

		SketchBasedJoinEstimator estimator = track(new SketchBasedJoinEstimator(store, omniConfig()));
		estimator.rebuild();

		List<TupleExpr> query = new ArrayList<>();
		for (int hop = 0; hop < predicates.length; hop++) {
			query.add(pattern("path" + hop, predicates[hop], "path" + (hop + 1)));
		}

		assertWithin50Percent("directed path", estimator.cardinality(query), roots * product(fanouts));
	}

	@Test
	void omniDirectedPathWithPredicateNoiseDoesNotCollapse() {
		int roots = 2_000;
		int noiseStatements = 80_000;
		int[] fanouts = { 3, 1, 4, 1, 2, 1 };
		IRI[] predicates = predicates("urn:omni-accuracy:noisy-path:p", fanouts.length);
		StubSketchStatementSource store = new StubSketchStatementSource();
		addPath(store, roots, predicates, fanouts, "urn:omni-accuracy:noisy-path:node:");
		for (int row = 0; row < noiseStatements; row++) {
			store.add(st(iri("urn:omni-accuracy:noisy-path:noise:s:" + row), predicates[row % predicates.length],
					iri("urn:omni-accuracy:noisy-path:noise:o:" + (row % 256))));
		}

		SketchBasedJoinEstimator estimator = track(new SketchBasedJoinEstimator(store, lmdbLikeOmniConfig()));
		estimator.rebuild();

		List<TupleExpr> query = pathPatterns(predicates, "noisyPath");
		SketchBasedJoinEstimator.OmniJoinDiagnostic diagnostic = estimator.diagnoseOmniOrderedConnectedJoin(query,
				Set.of());
		System.out.println("Noisy path OMNI diagnostic: " + diagnostic);

		assertWithin50Percent("noisy directed path", estimator.cardinality(query), roots * product(fanouts));
	}

	@Test
	void omniBridgedStarsPreserveFanoutAcrossPredicateEdges() {
		int rows = 20;
		int[] firstFanouts = { 1, 2, 1, 1, 1, 3, 1 };
		int[] secondFanouts = { 1, 1, 2, 1, 3, 1, 1 };
		int[] thirdFanouts = { 1, 2, 1, 2, 1, 1, 1 };
		IRI[] firstPredicates = predicates("urn:omni-accuracy:bridge:first:p", firstFanouts.length);
		IRI[] secondPredicates = predicates("urn:omni-accuracy:bridge:second:p", secondFanouts.length);
		IRI[] thirdPredicates = predicates("urn:omni-accuracy:bridge:third:p", thirdFanouts.length);
		IRI firstSecond = iri("urn:omni-accuracy:bridge:first-second");
		IRI secondThird = iri("urn:omni-accuracy:bridge:second-third");
		StubSketchStatementSource store = new StubSketchStatementSource();
		for (int row = 0; row < rows; row++) {
			Resource first = iri("urn:omni-accuracy:bridge:first:" + row);
			Resource second = iri("urn:omni-accuracy:bridge:second:" + row);
			Resource third = iri("urn:omni-accuracy:bridge:third:" + row);
			addStar(store, first, firstPredicates, firstFanouts, "urn:omni-accuracy:bridge:first-leaf:" + row);
			store.add(st(first, firstSecond, second));
			addStar(store, second, secondPredicates, secondFanouts, "urn:omni-accuracy:bridge:second-leaf:" + row);
			store.add(st(second, secondThird, third));
			addStar(store, third, thirdPredicates, thirdFanouts, "urn:omni-accuracy:bridge:third-leaf:" + row);
		}

		SketchBasedJoinEstimator estimator = track(new SketchBasedJoinEstimator(store, omniConfig()));
		estimator.rebuild();

		List<TupleExpr> query = new ArrayList<>();
		addStarPatterns(query, "first", firstPredicates, "firstLeaf");
		query.add(pattern("first", firstSecond, "second"));
		addStarPatterns(query, "second", secondPredicates, "secondLeaf");
		query.add(pattern("second", secondThird, "third"));
		addStarPatterns(query, "third", thirdPredicates, "thirdLeaf");

		long expected = (long) rows * product(firstFanouts) * product(secondFanouts) * product(thirdFanouts);
		assertWithin50Percent("bridged stars", estimator.cardinality(query), expected);
	}

