	private <T extends SketchBasedJoinEstimator> T track(T estimator) {
		estimators.add(estimator);
		return estimator;
	}

	private static SketchBasedJoinEstimator.Config omniConfig() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withSketchStrategy(SketchBasedJoinEstimator.SketchStrategy.OMNI)
				.withNominalEntries(2048)
				.withSubjectBucketCount(2048)
				.withPredicateBucketCount(128)
				.withObjectBucketCount(2048)
				.withContextBucketCount(64)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(5);
	}

	private static SketchBasedJoinEstimator.Config lmdbLikeOmniConfig() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withSketchStrategy(SketchBasedJoinEstimator.SketchStrategy.OMNI)
				.withNominalEntries(1024)
				.withSubjectBucketCount(1024)
				.withPredicateBucketCount(128)
				.withObjectBucketCount(1024)
				.withContextBucketCount(16)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(5);
	}

	private static void addPath(StubSketchStatementSource store, int roots, IRI[] predicates, int[] fanouts,
			String nodePrefix) {
		List<Resource> subjects = new ArrayList<>(roots);
		for (int rootIndex = 0; rootIndex < roots; rootIndex++) {
			subjects.add(iri(nodePrefix + "0:" + rootIndex));
		}
		for (int hop = 0; hop < predicates.length; hop++) {
			List<Resource> nextSubjects = new ArrayList<>(subjects.size() * fanouts[hop]);
			for (int subjectIndex = 0; subjectIndex < subjects.size(); subjectIndex++) {
				Resource subject = subjects.get(subjectIndex);
				for (int edge = 0; edge < fanouts[hop]; edge++) {
					Resource object = iri(nodePrefix + (hop + 1) + ':' + (subjectIndex * fanouts[hop] + edge));
					store.add(st(subject, predicates[hop], object));
					nextSubjects.add(object);
				}
			}
			subjects = nextSubjects;
		}
	}

	private static List<TupleExpr> pathPatterns(IRI[] predicates, String pathPrefix) {
		List<TupleExpr> query = new ArrayList<>();
		for (int hop = 0; hop < predicates.length; hop++) {
			query.add(pattern(pathPrefix + hop, predicates[hop], pathPrefix + (hop + 1)));
		}
		return query;
	}

	private static void addStar(StubSketchStatementSource store, Resource center, IRI[] predicates, int[] fanouts,
			String leafPrefix) {
		addPartialStar(store, center, predicates, fanouts, leafPrefix);
	}

	private static void addPartialStar(StubSketchStatementSource store, Resource center, IRI[] predicates,
			int[] fanouts, String leafPrefix) {
		for (int predicateIndex = 0; predicateIndex < fanouts.length; predicateIndex++) {
			for (int leafIndex = 0; leafIndex < fanouts[predicateIndex]; leafIndex++) {
				store.add(st(center, predicates[predicateIndex],
						iri(leafPrefix + ':' + predicateIndex + ':' + leafIndex)));
			}
		}
	}

	private static void addStarPatterns(List<TupleExpr> query, String center, IRI[] predicates, String leafPrefix) {
		for (int predicateIndex = 0; predicateIndex < predicates.length; predicateIndex++) {
			query.add(pattern(center, predicates[predicateIndex], leafPrefix + predicateIndex));
		}
	}

	private static StatementPattern pattern(String subjectVar, IRI predicate, String objectVar) {
		return new StatementPattern(Var.of(subjectVar), Var.of("predicate", predicate), Var.of(objectVar));
	}

	private static Statement st(Resource subject, IRI predicate, Value object) {
		return VF.createStatement(subject, predicate, object);
	}

	private static IRI[] predicates(String prefix, int count) {
		IRI[] predicates = new IRI[count];
		for (int i = 0; i < count; i++) {
			predicates[i] = iri(prefix + i);
		}
		return predicates;
	}

	private static IRI iri(String iri) {
		return VF.createIRI(iri);
	}

	private static long product(int[] values) {
		long product = 1L;
		for (int value : values) {
			product *= value;
		}
		return product;
	}

	private static void assertWithin50Percent(String label, double estimate, long actual) {
		double relativeError = Math.abs(estimate - actual) / Math.max(1.0d, actual);
		assertTrue(Double.isFinite(estimate) && estimate >= 0.0d,
				() -> label + " estimate should be finite and non-negative: " + estimate);
		assertTrue(relativeError <= MAX_RELATIVE_ERROR,
				() -> label + " OMNI estimate " + estimate + " should be within 50% of actual " + actual
						+ " (relative error " + relativeError + ')');
	}
